// src/components/PinsLayer.jsx
import React from "react";
import { Marker, Popup, LayerGroup } from "react-leaflet";
import L from "leaflet";
import { PIN_TYPES } from "./pinsConfig";

function makeIcon(typeKey = "rain") {
  const t = PIN_TYPES[typeKey] || PIN_TYPES.rain;
  const svg = encodeURIComponent(`
    <svg xmlns="http://www.w3.org/2000/svg" width="36" height="36">
      <circle cx="18" cy="18" r="16" fill="${t.color}" stroke="white" stroke-width="2"/>
      <text x="18" y="22" font-size="16" text-anchor="middle"> ${t.emoji} </text>
    </svg>
  `);
  return L.icon({
    iconUrl: `data:image/svg+xml;charset=UTF-8,${svg}`,
    iconSize: [36, 36],
    iconAnchor: [18, 36],
    popupAnchor: [0, -30],
  });
}

export default function PinsLayer({ pins = [] }) {
  return (
    <LayerGroup>
      {pins.map((p) => (
        <Marker key={p.id} position={[p.lat, p.lng]} icon={makeIcon(p.type)}>
          <Popup>
            <div className="text-sm">
              <div className="font-semibold">
                {(PIN_TYPES[p.type]?.emoji || "📍") + " "}
                {(PIN_TYPES[p.type]?.label || "Report")}
              </div>
              {p.message && <div className="mt-1">{p.message}</div>}
              <div className="mt-2 text-[11px] text-gray-400">
                {p.user ? `By ${p.user} • ` : ""}{new Date(p.timestamp).toLocaleString()}
              </div>
            </div>
          </Popup>
        </Marker>
      ))}
    </LayerGroup>
  );
}
